<template>
  <div class="flex-direction-column">
    <!-- 日志内容部分 -->
    <div
      class="g-page-container-with-header"
      v-for="dev in systemDataList"
      :key="dev.devid"
    >
      <div class="container-header flex-space-between">
        <span class="title">{{ dev.devname }}</span>
        <div class="g-button" @click="handleGetLogRow(dev)">获取日志</div>
      </div>
      <div class="container-content">
        <div class="value">
          <div v-for="(entry, index) in logMap[dev.devid]" :key="index">
            <template v-if="typeof entry === 'string'">
              {{ entry }}
            </template>
            <template v-else-if="entry.url">
              <a :href="entry.url" target="_blank">{{ entry.url }}</a>
            </template>
          </div>
        </div>
      </div>
    </div>

    <!-- el-dialog -->
    <el-dialog
      v-model="dialogVisible"
      title="日志提取参数"
      width="30%"
      :close-on-click-modal="false"
    >
      <el-form label-width="100px" label-position="left">
        <el-form-item label="日志类型">
          <el-select v-model="logForm.type" placeholder="请选择">
            <el-option label="系统日志" value="sys" />
            <el-option label="内核日志" value="kernel" />
            <el-option label="应用日志" value="app" />
            <el-option label="bag日志" value="bag" />
          </el-select>
        </el-form-item>

        <el-form-item label="起始时间">
          <el-date-picker
            v-model="logForm.start"
            type="datetime"
            placeholder="开始时间"
            format="YYYY-MM-DD HH:mm:ss"
            value-format="YYYY-MM-DD_HH-mm-ss"
          />
        </el-form-item>

        <el-form-item label="结束时间">
          <el-date-picker
            v-model="logForm.end"
            type="datetime"
            placeholder="结束时间"
            format="YYYY-MM-DD HH:mm:ss"
            value-format="YYYY-MM-DD_HH-mm-ss"
          />
        </el-form-item>
      </el-form>

      <template #footer>
        <span class="dialog-footer">
          <el-button @click="dialogVisible = false">取消</el-button>
          <el-button type="primary" @click="handleLogSubmit">获取</el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

<script setup>
import { ref, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'
import { ElMessage, ElDialog, ElButton } from 'element-plus'

const store = useWslStore()
const { received } = storeToRefs(store)
const { sendLogExtractCommand } = useCommand(store)

const logMap = ref({}) // 保存日志内容（拼接）
const currentLogDevice = ref(null) // 当前点击的设备

// 设备列表
// const systemDataList = computed(() => {
//   const data = received.value?.statusData?.systemDataList
//   return data
// })
const systemDataList = ref([])
watch(
  () => received.value?.statusData?.systemDataList,
  (newList) => {
    if (Array.isArray(newList) && newList.length) {
      systemDataList.value = newList // 仅当有新列表时才替换
    }
  },
  { immediate: true } // 页面初次加载也跑一次
)

// 弹窗控制
const dialogVisible = ref(false)
const logForm = ref({
  type: '',
  start: '',
  end: ''
})

// 点击按钮：记录当前设备并弹窗
const handleGetLogRow = (dev) => {
  currentLogDevice.value = dev
  dialogVisible.value = true
}

//提交请求并生成随机 userdata
const handleLogSubmit = () => {
  const { type, start, end } = logForm.value

  if (!type || !start || !end) {
    ElMessage.warning('请填写完整信息')
    return
  }

  const devid = String(currentLogDevice.value.devid)
  // const userdata = `log_${Date.now()}_${Math.floor(Math.random() * 10000)}`

  // 重置该设备日志
  logMap.value[devid] = []

  // sendLogExtractCommand(devid, type, start, end, userdata)
  sendLogExtractCommand(devid, type, start, end)
  dialogVisible.value = false
}

//监听推送追加日志内容
watch(
  () => received.value?.logResponse,
  (logResponse) => {
    if (!logResponse?.dataList?.length || !currentLogDevice.value) return

    const targetDevid = currentLogDevice.value.devid

    const wsUrl =
      process.env.NODE_ENV === 'development'
        ? process.env.VUE_APP_WS_URL
        : `ws://${window.location.hostname}:7123/status`
    const url = new URL(wsUrl)
    const host = url.hostname
    const port =
      process.env.NODE_ENV === 'development' ? '8080' : window.location.port

    const logList = logMap.value[targetDevid] || []

    logResponse.dataList.forEach((item) => {
      if (item.status === 'finish' && received.value?.errorCode === 0) {
        logList.push({
          url: `http://${host}:${port}${item.packageName || ''}`
        })
      } else if (item.logMessage) {
        logList.push(item.logMessage)
      }
    })

    logMap.value[targetDevid] = logList
  },
  { deep: true }
)

//watch 监听日志提取结果
watch(
  () => received.value,
  (resp) => {
    if (!resp || !resp.logResponse) return
    // if (!resp) return

    const { errorCode, errorMessage } = resp

    if (typeof errorCode === 'number' && errorCode !== 0) {
      ElMessage({
        type: 'error',
        message: `日志提取失败：${errorMessage || '未知错误'}`,
        duration: 0,
        showClose: true
      })
    }
  }
)
</script>

<style lang="less" scoped>
.value {
  white-space: pre-line;
  font-family: monospace;
  line-height: 1.6;

  a {
    color: #1669bc;
    text-decoration: underline;
    word-break: break-all;
  }
}

.g-page-container-with-header {
  max-height: 700px;
  display: flex;
  flex-direction: column;

  .container-header {
    /* 固定顶部，不滚动 */
    flex-shrink: 0;
  }
  .container-content {
    /* 内容滚动 */
    flex: 1;
    overflow-y: auto;
  }
}
</style>
